+namespace Microsoft.Integration.Shopify;
+
+/// <summary>
+/// Clears Shopify identifiers when copying posted sales invoices.
+/// </summary>
+codeunit 30366 "Shpfy Copy Sales Document"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnCopySalesDocOnAfterTransferPostedInvoiceFields', '', false, false)]
+    local procedure ClearShopifyFieldsOnCopy(var ToSalesHeader: Record "Sales Header"; SalesInvoiceHeader: Record "Sales Invoice Header"; OldSalesHeader: Record "Sales Header")
+    begin
+        if ToSalesHeader."Document Type" <> ToSalesHeader."Document Type"::Invoice then
+            exit;
+
+        if (ToSalesHeader."Shpfy Order Id" = 0) and (ToSalesHeader."Shpfy Order No." = '') then
+            exit;
+
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+    end;
+}

